import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import MainMenu from './components/MainMenu';
import CreateGame from './pages/CreateGame';
import StartGame from './pages/StartGame';
import SetGame from './pages/SetGame';
import PlayersSetting from './pages/PlayersSetting';
import History from './pages/History';

function App() {
  return (
    <Router>
      <div style={styles.appContainer}>
        <Routes>
          <Route path="/" element={<MainMenu />} />
          <Route path="/start-game" element={<StartGame />} />
          <Route path="/create-game" element={<CreateGame />} />
          <Route path="/set-game" element={<SetGame />} />
          <Route path="/players" element={<PlayersSetting />} />
          <Route path="/history" element={<History />} />
        </Routes>
      </div>
    </Router>
  );
}

const styles = {
  appContainer: {
    backgroundColor: '#D6F8D6', // Nyanza background
    minHeight: '100vh',
    padding: '20px',
    fontFamily: "'Press Start 2P', cursive", // Old-school font
  },
};

export default App;
